import{_ as e,o as a,c as r,ae as d}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Cohorts (New)","description":"","frontmatter":{"title":"Cohorts (New)","slug":"cohorts-new"},"headers":[],"relativePath":"marketer-hub/cohorts-new.md","filePath":"marketer-hub/cohorts-new.md"}'),n={name:"marketer-hub/cohorts-new.md"};function o(s,t,i,u,l,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The <a href="https://branchdocs.app.link/cohorts-to-analysis-cohorts" target="_blank" rel="noreferrer">Cohorts</a> data source lets you track user behavior over time by grouping users based on their app install acquisition dates. Use it to analyze retention, lifetime value, and campaign ROI so you can understand long-term user performance and make informed investment decisions.</p><p>To learn more about Analysis, read our <a href="./analysis-dashboards-overview-new.html">Dashboards Overview</a> article. To learn about all available data sources, read our <a href="./analysis-data-sources-new.html">Analysis Data Sources</a> article.</p><h4 id="packaging" tabindex="-1">Packaging <a class="header-anchor" href="#packaging" aria-label="Permalink to &quot;Packaging&quot;">​</a></h4><p>Cohorts is available as part of certain Branch plans. For more information, please see our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing page</a> or <a href="https://branchdocs.app.link/cohorts-to-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p><h2 id="when-to-use-this-data-source" tabindex="-1">When to use this data source <a class="header-anchor" href="#when-to-use-this-data-source" aria-label="Permalink to &quot;When to use this data source&quot;">​</a></h2><p>Use the Cohorts data source when you want to understand how groups of users behave after they install your app. Cohorts ties all downstream user actions (purchases, logins, uninstalls, and more) back to the date and source of the original install. This makes it useful for questions about retention, payback periods, and long-term campaign quality.</p><p>Common use cases include:</p><ul><li><strong>Retention analysis</strong>: See how many users from a specific install week are still opening your app over time.</li><li><strong>Lifetime value (LTV)</strong>: Track cumulative revenue and purchase events per cohort to understand how much value different acquisition sources generate over time.</li><li><strong>Campaign ROI</strong>: Compare cost against downstream revenue, ROAS, and ROI to determine which campaigns pay for themselves and how quickly.</li><li><strong>Ad partner benchmarking</strong>: Break out cohort performance by Ad Partner Name, Ad Set Name, or Creative Name to see which partners and creatives deliver users with the strongest long-term engagement.</li></ul><p>This data source includes cohort-specific dimensions and measures, such as Users, Cost Default, Revenue, ROAS, and ROI. These are not available in the standard <a href="./analysis-data-sources-new.html#cohorts">Activity</a> data source.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Re-engagement cohort data is not yet available in Analysis. The Cohorts data source currently supports acquisition (install) cohorts only.</p></div><h2 id="how-cohort-data-is-organized" tabindex="-1">How cohort data is organized <a class="header-anchor" href="#how-cohort-data-is-organized" aria-label="Permalink to &quot;How cohort data is organized&quot;">​</a></h2><p>Every row in the Cohorts data source is anchored to an install cohort, which a group of users who installed your app during the same time period. The dimensions on each row (such as Ad Partner Name, Campaign Name, and OS) describe the attributes of that install, while the measures (such as Purchase, Open, and Revenue) reflect the downstream actions those users took after installing.</p><p>In this way, Cohorts differs from the <a href="./analysis-data-sources-new.html#activity1">Activity</a> and <a href="./analysis-data-sources-new.html#activity-extended">Activity Extended</a> data sources, which report on events independently of when the user was acquired.</p><h2 id="use-cohorts" tabindex="-1">Use Cohorts <a class="header-anchor" href="#use-cohorts" aria-label="Permalink to &quot;Use Cohorts&quot;">​</a></h2><p>To access Cohorts, go to <strong>Analysis &gt;</strong> <a href="https://branchdocs.app.link/cohorts-to-analysis-cohorts" target="_blank" rel="noreferrer"><strong>Cohorts</strong></a> in Branch.</p><p>The Cohorts data source uses configurable day ranges to measure cumulative user behavior at different intervals after install. These are labeled:</p><ul><li>D Range A</li><li>D Range B</li><li>D Range C</li></ul><p>Each one defines a number of days post-install to track. You can set up to three day ranges.</p><p>To adjust these day ranges, select the <strong>D Range</strong> filter parameters at the top of your <a href="https://branchdocs.app.link/cohorts-to-analysis-cohorts" target="_blank" rel="noreferrer">Cohorts</a> dashboard and enter an integer value for each one.</p><p>Note that the Cohorts data source requires a rolling date window (e.g. &quot;Last 30 Days&quot;) and only supports day-level granularity.</p><h4 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h4><p>Imagine you set the ranges to:</p><ul><li>D Range A = 7</li><li>D Range B = 14</li><li>D Range C = 21</li></ul><p>In this case, measure columns like Revenue and Purchase will appear with A, B, and C suffixes (e.g. Revenue A, Revenue B, Revenue C). Each value is cumulative, meaning Revenue A at <strong>D Range A</strong> = 7 represents the total revenue generated from install through day 7, not just day 7 alone.</p><h2 id="use-ivy-for-insights" tabindex="-1">Use Ivy for insights <a class="header-anchor" href="#use-ivy-for-insights" aria-label="Permalink to &quot;Use Ivy for insights&quot;">​</a></h2><p>You can use <a href="./analysis-dashboards-overview-new.html#ai">Ivy</a> to ask questions about your cohort data. To make sure Ivy uses the Cohorts data source, select the <strong>Ivy</strong> button on a Cohorts <a href="./analysis-dashboards-overview-new.html#widgets">widget</a> rather than the Ask Ivy prompt bar at the top of the dashboard. Prompting from the widget gives Ivy the correct data source context automatically.</p><p>When using the Cohorts data source with Ivy, try prompts like:</p><ul><li>&quot;Show me 30-day purchase revenue by install cohort for the last 3 months.&quot;</li><li>&quot;Compare ROAS across my top 5 ad partners for users who installed this quarter.&quot;</li><li>&quot;What&#39;s the retention rate (opens) for iOS versus Android cohorts over the past 60 days?&quot;</li><li>&quot;Which campaign had the highest install-to-purchase conversion rate last month?&quot;</li><li>&quot;Break down cost versus revenue by ad set for my Meta campaigns.&quot;</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Be specific about time periods in your prompts. Because cohort analysis compares user behavior across different install windows, saying &quot;users who installed in the last 30 days&quot; is more useful than &quot;recent users.&quot;</p></div><h2 id="fields-reference" tabindex="-1">Fields reference <a class="header-anchor" href="#fields-reference" aria-label="Permalink to &quot;Fields reference&quot;">​</a></h2><p>The following fields are available in the Cohorts data source.</p><table tabindex="0"><thead><tr><th>Field</th><th>Field Type</th><th>Description</th></tr></thead><tbody><tr><td>Achieve Level</td><td>Measure</td><td>Total count of Achieve Level Branch Standard Events</td></tr><tr><td>Achieve Level Unique</td><td>Measure</td><td>Total unique count of Achieve Level events</td></tr><tr><td>Ad Partner 3p</td><td>Dimension</td><td>The attributed install&#39;s ad partner via their Branch code (3p)</td></tr><tr><td>Ad Partner Name</td><td>Dimension</td><td>The attributed install&#39;s ad partner name</td></tr><tr><td>Ad Set Id</td><td>Dimension</td><td>The attributed install&#39;s ad set ID</td></tr><tr><td>Ad Set Name</td><td>Dimension</td><td>The attributed install&#39;s ad set name</td></tr><tr><td>Add Payment Info</td><td>Measure</td><td>Total count of Add Payment Info Branch Standard Events</td></tr><tr><td>Add Payment Info Unique</td><td>Measure</td><td>Unique Count of Add Payment Info events</td></tr><tr><td>Add to Cart</td><td>Measure</td><td>Total count of Add to Cart Branch Standard Events</td></tr><tr><td>Add to Cart Unique</td><td>Measure</td><td>Unique Count of Add to Cart events</td></tr><tr><td>Add to Wishlist</td><td>Measure</td><td>Total count of Add to Wishlist Branch Standard Events</td></tr><tr><td>Add to Wishlist Unique</td><td>Measure</td><td>Total unique count of Add to Wishlist events</td></tr><tr><td>Agency Id</td><td>Dimension</td><td>The attributed install&#39;s agency ID</td></tr><tr><td>Agency Name</td><td>Dimension</td><td>The attributed install&#39;s agency name</td></tr><tr><td>App Id</td><td>Dimension</td><td>The Branch App Id</td></tr><tr><td>App Name</td><td>Dimension</td><td>The Branch App Name</td></tr><tr><td>Attributed</td><td>Dimension</td><td>Indicates whether Branch was able to attribute the conversion event</td></tr><tr><td>Branch Channel</td><td>Dimension</td><td>Identifies which Branch product or feature measured the attributed event</td></tr><tr><td>Campaign ID</td><td>Dimension</td><td>The attributed install&#39;s campaign ID</td></tr><tr><td>Campaign Name</td><td>Dimension</td><td>The attributed install&#39;s campaign name</td></tr><tr><td>Channel</td><td>Dimension</td><td>The attributed install&#39;s Channel</td></tr><tr><td>Click Ad</td><td>Measure</td><td>Total count of Click Ad Branch Standard Events</td></tr><tr><td>Click Ad Unique</td><td>Measure</td><td>Total unique count of Click Ad events</td></tr><tr><td>Complete Registration Unique</td><td>Measure</td><td>Total unique count of Complete Registration events</td></tr><tr><td>Complete Stream</td><td>Measure</td><td>Total count of Complete Stream Branch Standard Events</td></tr><tr><td>Complete Stream Unique</td><td>Measure</td><td>Total unique count of Complete Stream events</td></tr><tr><td>Complete Tutorial</td><td>Measure</td><td>Total count of Complete Tutorial Branch Standard Events</td></tr><tr><td>Complete Tutorial Unique</td><td>Measure</td><td>Total unique count of Complete Tutorial events</td></tr><tr><td>Cost Default</td><td>Measure</td><td>The spend on the paid media campaign</td></tr><tr><td>Creative Id</td><td>Dimension</td><td>The attributed install&#39;s creative ID</td></tr><tr><td>Creative Name</td><td>Dimension</td><td>The attributed install&#39;s creative name</td></tr><tr><td>Custom Event Template 0</td><td>Measure</td><td>Template to set up count of your Branch Custom Event KPI</td></tr><tr><td>Custom Event Unique Template 0</td><td>Measure</td><td>Template to set up unique count of your Branch Custom Event KPI</td></tr><tr><td>Date</td><td>Dimension</td><td>Time-series date</td></tr><tr><td>Event Name</td><td>Dimension</td><td>The name of the Branch event</td></tr><tr><td>Feature</td><td>Dimension</td><td>Indicates what Branch feature or link campaign was attributed on the install</td></tr><tr><td>Geo Country Code</td><td>Dimension</td><td>Two-letter global geo country code</td></tr><tr><td>Initiate Purchase</td><td>Measure</td><td>Total count of Initiate Purchase Branch Standard Events</td></tr><tr><td>Initiate Purchase Unique</td><td>Measure</td><td>Total unique count of Initiate Purchase events</td></tr><tr><td>Initiate Stream</td><td>Measure</td><td>Total count of Initiate Stream Branch Standard Events</td></tr><tr><td>Initiate Stream Unique</td><td>Measure</td><td>Total unique count of Initiate Stream events</td></tr><tr><td>Install</td><td>Measure</td><td>Total count of Install Branch Standard Events</td></tr><tr><td>Install Unique</td><td>Measure</td><td>Total unique count of Install events</td></tr><tr><td>Invite</td><td>Measure</td><td>Total count of Invite Branch Standard Events</td></tr><tr><td>Invite Unique</td><td>Measure</td><td>Total unique count of Invite events</td></tr><tr><td>Keyword Id</td><td>Dimension</td><td>The attributed install&#39;s keyword ID</td></tr><tr><td>Keyword Name</td><td>Dimension</td><td>The attributed install&#39;s keyword name</td></tr><tr><td>Login</td><td>Measure</td><td>Total count of Login Branch Standard Events</td></tr><tr><td>Login Unique</td><td>Measure</td><td>Total unique count of Login events</td></tr><tr><td>Open</td><td>Measure</td><td>Total count of Open Branch Standard Events</td></tr><tr><td>Open Unique</td><td>Measure</td><td>Total unique count of Open events</td></tr><tr><td>Opt In</td><td>Measure</td><td>Total count of Opt In Branch Standard Events</td></tr><tr><td>Opt In Unique</td><td>Measure</td><td>Total unique count of Opt In events</td></tr><tr><td>Opt Out</td><td>Measure</td><td>Total count of Opt Out Branch Standard Events</td></tr><tr><td>Opt Out Unique</td><td>Measure</td><td>Total unique count of Opt Out events</td></tr><tr><td>OS</td><td>Dimension</td><td>Indicates the Operating System of the device as retrieved via the Branch SDK</td></tr><tr><td>Pageview</td><td>Measure</td><td>Total count of Pageview Branch Standard Events</td></tr><tr><td>Pageview Unique</td><td>Measure</td><td>Total unique count of Pageview events</td></tr><tr><td>Platform</td><td>Dimension</td><td>Indicates the Platform of the device as retrieved via the Branch SDK</td></tr><tr><td>Purchase</td><td>Measure</td><td>Total count of Purchase Branch Standard Events</td></tr><tr><td>Purchase Unique</td><td>Measure</td><td>Total unique count of Purchase events</td></tr><tr><td>Rate</td><td>Measure</td><td>Total count of Rate Branch Standard Events</td></tr><tr><td>Rate Unique</td><td>Measure</td><td>Total unique count of Rate events</td></tr><tr><td>Registration</td><td>Measure</td><td>Total count of Registration Branch Standard Events</td></tr><tr><td>Reinstall</td><td>Measure</td><td>Total count of Reinstall Branch Standard Events</td></tr><tr><td>Reinstall Unique</td><td>Measure</td><td>Total unique count of Reinstall events</td></tr><tr><td>Reserve</td><td>Measure</td><td>Total count of Reserve Branch Standard Events</td></tr><tr><td>Reserve Unique</td><td>Measure</td><td>Total unique count of Reserve events</td></tr><tr><td>Revenue</td><td>Measure</td><td>The tracked revenue from Branch commerce events</td></tr><tr><td>ROAS</td><td>Measure</td><td>Return on ad spend</td></tr><tr><td>ROI</td><td>Measure</td><td>Return on investment</td></tr><tr><td>Search</td><td>Measure</td><td>Total count of Search Branch Standard Events</td></tr><tr><td>Search Unique</td><td>Measure</td><td>Total unique count of Search events</td></tr><tr><td>Secondary Publisher</td><td>Dimension</td><td>The attributed install&#39;s secondary publisher</td></tr><tr><td>Share</td><td>Measure</td><td>Total count of Share Branch Standard Events</td></tr><tr><td>Share Unique</td><td>Measure</td><td>Total unique count of Share events</td></tr><tr><td>Spend Credits</td><td>Measure</td><td>Total count of Spend Credits Branch Standard Events</td></tr><tr><td>Spend Credits Unique</td><td>Measure</td><td>Total unique count of Spend Credits events</td></tr><tr><td>Start Trial</td><td>Measure</td><td>Total count of Start Trial Branch Standard Events</td></tr><tr><td>Start Trial Unique</td><td>Measure</td><td>Total unique count of Start Trial events</td></tr><tr><td>Subscribe</td><td>Measure</td><td>Total count of Subscribe Branch Standard Events</td></tr><tr><td>Subscribe Unique</td><td>Measure</td><td>Total unique count of Subscribe events</td></tr><tr><td>Total Count</td><td>Measure</td><td>The total count of rows</td></tr><tr><td>Touch Type</td><td>Dimension</td><td>Indicates whether the attributed install event was an Impression, Click, or other touch type.</td></tr><tr><td>Uninstall</td><td>Measure</td><td>Total count of Uninstall Branch Standard Events</td></tr><tr><td>Uninstall Unique</td><td>Measure</td><td>Total unique count of Uninstall events</td></tr><tr><td>Unique Count</td><td>Measure</td><td>The total unique user count of rows</td></tr><tr><td>Unlock Achievement</td><td>Measure</td><td>Total count of Unlock Achievement Branch Standard Events</td></tr><tr><td>Unlock Achievement Unique</td><td>Measure</td><td>Total unique count of Unlock Achievement events</td></tr><tr><td>Users</td><td>Measure</td><td>The unique count of users in the install cohort</td></tr><tr><td>View Ad</td><td>Measure</td><td>Total count of View Ad Branch Standard Events</td></tr><tr><td>View Ad Unique</td><td>Measure</td><td>Total unique count of View Ad events</td></tr><tr><td>View Cart</td><td>Measure</td><td>Total count of View Cart Branch Standard Events</td></tr><tr><td>View Cart Unique</td><td>Measure</td><td>Total unique count of View Cart events</td></tr><tr><td>View Item</td><td>Measure</td><td>Total count of View Item Branch Standard Events</td></tr><tr><td>View Item Unique</td><td>Measure</td><td>Total unique count of View Item events</td></tr><tr><td>View Items</td><td>Measure</td><td>Total count of View Items Branch Standard Events</td></tr><tr><td>View Items Unique</td><td>Measure</td><td>Total unique count of View Items events</td></tr><tr><td>Web Session Start</td><td>Measure</td><td>Total count of Web Session Start Branch Standard Events</td></tr><tr><td>Web Session Start Unique</td><td>Measure</td><td>Total unique count of Web Session Start events</td></tr></tbody></table><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>How do I access the Cohorts data source?</summary><p>Navigate to <strong>Analysis &gt;</strong> <a href="https://branchdocs.app.link/cohorts-to-analysis-cohorts" target="_blank" rel="noreferrer"><strong>Cohorts</strong></a> in Branch.</p></details><details><summary>What do the A, B, and C suffixes on measure columns mean?</summary><p>Measure columns like Revenue A, Revenue B, and Revenue C correspond to the three configurable day ranges (<strong>D Range A</strong>, <strong>D Range B</strong>, and <strong>D Range C</strong>). Each value is cumulative. For example, if D Range A is set to 7, then Revenue A is the total revenue from install through day 7.</p></details><details><summary>Does Cohorts use rolling or fixed date ranges?</summary><p>The Cohorts data source requires a rolling date window (e.g. &quot;Last 30 Days&quot;).</p></details><details><summary>What kind of data granularity is supported?</summary><p>Cohorts supports day-level granularity.</p></details><details><summary>Why is Ivy returning unexpected results when I ask about cohort data?</summary><p>The <strong>Ask Ivy</strong> prompt bar at the top of a dashboard may default to a different data source (such as Activity). To ensure Ivy queries the Cohorts data source, select the <strong>Ivy</strong> button directly on a Cohorts widget instead of using the top-of-dashboard prompt bar.</p></details><details><summary>Can I use Cohorts for re-engagement analysis?</summary><p>Not at this time. The Cohorts data source currently supports acquisition (install) cohorts only.</p></details><details><summary>Is the Cohorts data source available in all Branch plans?</summary><p>Availability of Cohorts depends on your Branch plan. Learn more on our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing page</a> or <a href="https://branchdocs.app.link/e/analysis-sales" target="_blank" rel="noreferrer">contact our Sales team</a>.</p></details>',41)])])}const p=e(n,[["render",o]]);export{m as __pageData,p as default};
